    //Copy of the standard private method
    private PurchTable UBSgetPurchTable(RecId  _recId)
    {
        if (!purchTable)
        {
            purchTable = PurchTable::findRecId(_recId);
        }

        return purchTable;
    }

    public UBSPurchReqTotalAmount parmCalcPurchReqTotalAmount(CompanyId _companyId, TableId _tableId, RecId _recId)
    {
        Amount  purchReqTotalAmount = 0;

        this.UBSgetPurchTable(_recId);

        if (purchTable)
        {
            PurchReqLine purchReqLine;
            while select LineAmount from purchReqLine 
                where purchReqLine.PurchId == purchTable.PurchId
                {
                    purchReqTotalAmount += purchReqLine.LineAmount;
                }
        }

        return purchReqTotalAmount;
    }
